import java.util.*;
import java.text.*;
import org.apache.commons.lang3.time.FastDateFormat;

public class TestWeekIssue {
    public static void main(String[] args) {
        Locale locale = new Locale("sv", "SE");

        Calendar cal = Calendar.getInstance();
        cal.set(2010, 0, 1, 12, 0, 0); // Jan 1, 2010
        Date d = cal.getTime();

        System.out.println("Date: " + d);
        System.out.println("Calendar week of year: " + cal.get(Calendar.WEEK_OF_YEAR));
        System.out.println("Calendar day of week: " + cal.get(Calendar.DAY_OF_WEEK));

        // Test using standard SimpleDateFormat
        SimpleDateFormat sdf = new SimpleDateFormat("EEEE', week 'ww", locale);
        System.out.println("SimpleDateFormat result: " + sdf.format(d));

        // Test using FastDateFormat
        FastDateFormat fdf = FastDateFormat.getInstance("EEEE', week 'ww", locale);
        System.out.println("FastDateFormat result: " + fdf.format(d));

        System.out.println("Expected: fredag, week 53");
    }
}

